mapper.select:
SELECT A.* ,(CASE WHEN PG.BID_BEGIN_DATE IS NULL THEN '-' ELSE (SUBSTR(PG.BID_BEGIN_DATE, 1, 4) '-' SUBSTR(PG.BID_BEGIN_DATE, 5, 2) '-' SUBSTR(PG.BID_BEGIN_DATE, 7, 2) ' ' SUBSTR(PG.BID_BEGIN_TIME, 1, 2) ':' SUBSTR(PG.BID_BEGIN_TIME, 3, 2)) END) AS BID_BEGIN_DATETIME ,(CASE WHEN PG.BID_END_DATE IS NULL THEN '-' ELSE (SUBSTR(PG.BID_END_DATE, 1, 4) '-' SUBSTR(PG.BID_END_DATE, 5, 2) '-' SUBSTR(PG.BID_END_DATE, 7, 2) ' ' SUBSTR(PG.BID_END_TIME, 1, 2) ':' SUBSTR(PG.BID_END_TIME, 3, 2)) END) AS BID_END_DATETIME ,(CASE WHEN PG.OPEN_DATE IS NULL THEN '-' ELSE (SUBSTR(PG.OPEN_DATE, 1, 4) '-' SUBSTR(PG.OPEN_DATE, 5, 2) '-' SUBSTR(PG.OPEN_DATE, 7, 2) ' ' SUBSTR(PG.OPEN_TIME, 1, 2) ':' SUBSTR(PG.OPEN_TIME, 3, 2)) END) AS OPEN_DATETIME FROM ( SELECT HD.GATE_CD , HD.BUYER_CD , HD.BID_NUM , HD.BID_CNT , PG.VOTE_CNT ,getBuyerNames(HD.GATE_CD, HD.BUYER_CD, 'BID', HD.BID_NUM, HD.BID_CNT, null, #{ses.langCd}) AS BUYER_NM , HD.ANN_NO , HD.ANN_ITEM , HD.ANN_DATE , HD.CONT_TYPE1 , HD.CONT_TYPE2 , HD.CONT_TYPE3 , SUBSTR(HD.APP_END_DATE, 1, 4) '-' SUBSTR(HD.APP_END_DATE, 5, 2) '-' SUBSTR(HD.APP_END_DATE, 7, 2) ' ' SUBSTR(HD.APP_END_TIME, 1, 2) ':' SUBSTR(HD.APP_END_TIME, 3, 2) AS APP_END_DATETIME ,getBidProgressCd(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, 'CD') AS BID_STATUS ,getBidProgressCd(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, 'LOC') AS BID_STATUS_LOC , HD.BID_STATUS AS ORI_BID_STATUS , HD.BID_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.BID_USER_ID, #{ses.langCd}) AS BID_USER_NM , HD.OPEN_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.OPEN_USER_ID, #{ses.langCd}) AS OPEN_USER_NM , HD.EV_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.EV_USER_ID, #{ses.langCd}) AS EV_USER_NM , HD.SIGN_STATUS , HD.APP_END_DATE , HD.TECH_EV_TYPE ,(CASE WHEN PG.OPEN_DATE IS NULL THEN 'N' WHEN SYSDATE >= TO_DATE(PG.OPEN_DATE PG.OPEN_TIME, 'YYYYMMDDHH24MISS') THEN 'Y' ELSE 'N' END) AS OPEN_DATE_PASS_FLAG ,(CASE WHEN (HD.CONT_TYPE2 = 'NE' AND HD.TECH_EV_TYPE = '20') THEN (CASE WHEN (SELECT COUNT(EU.EU_SQ) AS NON_FINISH_CNT FROM STOCBDEU EU WHERE EU.GATE_CD = HD.GATE_CD AND EU.BUYER_CD = HD.BUYER_CD AND EU.EI_NUM = HD.EI_NUM AND EU.PROGRESS_CD != '300' AND EU.DEL_FLAG = '0') > 0 THEN 'N' ELSE 'Y' END) ELSE 'Y' END) AS OPEN_POSSIBLE_FLAG ,(CASE WHEN HD.ESTM_TYPE IN ('SE', 'PE') THEN (CASE WHEN (SELECT COUNT(ES.BID_CNT) AS NON_FINISH_CNT FROM STOCBDES ES WHERE ES.GATE_CD = HD.GATE_CD AND ES.BUYER_CD = HD.BUYER_CD AND ES.BID_NUM = HD.BID_NUM AND ES.BID_CNT = HD.BID_CNT AND ES.SIGN_STATUS = 'E' AND ES.ESTM_CONFIRM_DATE IS NOT NULL AND ES.DEL_FLAG = '0') > 0 THEN 'Y' ELSE 'N' END) ELSE 'Y' END) AS ESTM_FINISH_FLAG ,(CASE WHEN (HD.CONT_TYPE2 = 'NE' AND HD.TECH_EV_TYPE = '10') THEN (CASE WHEN (SELECT COUNT(SP.VENDOR_CD) AS NON_FINISH_CNT FROM STOCBDSP SP WHERE SP.GATE_CD = HD.GATE_CD AND SP.BUYER_CD = HD.BUYER_CD AND SP.BID_NUM = HD.BID_NUM AND SP.BID_CNT = HD.BID_CNT AND SP.VOTE_CNT = PG.VOTE_CNT AND SP.DEL_FLAG = '0' AND SP.TECH_SCORE IS NULL) > 0 THEN 'N' ELSE 'Y' END) ELSE 'Y' END) AS TECH_OPEN_POSSIBLE_FLAG ,(SELECT V.VOTE_CNT FROM ( SELECT VOTE_CNT, RANK() OVER (PARTITION BY PG.GATE_CD, PG.BUYER_CD, PG.BID_NUM, PG.BID_CNT ORDER BY PG.MOD_DATE DESC) AS RANK FROM STOCBDPG PG WHERE PG.GATE_CD = HD.GATE_CD AND PG.BUYER_CD = HD.BUYER_CD AND PG.BID_NUM = HD.BID_NUM AND PG.BID_CNT = HD.BID_CNT AND PG.DEL_FLAG = '0' ) V WHERE V.RANK = 1) AS PRECENT_VOTE , PG.PERIOD_MOD_RSN , PG.PERIOD_MOD_DATE -- 구매관리 > 입찰관리 > 입찰진행 (CBDR0030)의 "업체수" 표시 쿼리문 추가 ,(SELECT TO_CHAR(SUM((JOIN_VENDOR_CNT, 0))) '/' TO_CHAR(SUM((TOT_VENDOR_CNT, 0))) FROM ( SELECT COUNT(DISTINCT VENDOR_CD) AS JOIN_VENDOR_CNT , 0 AS TOT_VENDOR_CNT FROM STOCBDVO WHERE GATE_CD = HD.GATE_CD AND BUYER_CD = HD.BUYER_CD AND BID_NUM = HD.BID_NUM AND BID_CNT = HD.BID_CNT AND VOTE_CNT = PG.VOTE_CNT AND VOTE_DATE IS NOT NULL AND (BID_CANCEL_FLAG, '0') = '0' AND DEL_FLAG = '0' UNION ALL SELECT 0 AS JOIN_VENDOR_CNT , COUNT(DISTINCT VENDOR_CD) AS TOT_VENDOR_CNT FROM STOCBDAP WHERE GATE_CD = HD.GATE_CD AND BUYER_CD = HD.BUYER_CD AND BID_NUM = HD.BID_NUM AND BID_CNT = HD.BID_CNT AND APP_DATE IS NOT NULL -- 입찰신청일자 AND FINAL_FLAG = '500' -- 입찰신청 : 적합 AND (EV_FINAL_FLAG = '500' OR EV_FINAL_FLAG IS NULL) -- 평가결과 : 적합 또는 평가결과 없는 경우 AND DEL_FLAG = '0')) AS QUOT_VENDOR_CNT -- 투찰업체수/신청업체수 ,(SELECT COUNT(DISTINCT VENDOR_CD) FROM STOCBDVO WHERE GATE_CD = HD.GATE_CD AND BUYER_CD = HD.BUYER_CD AND BID_NUM = HD.BID_NUM AND BID_CNT = HD.BID_CNT AND VOTE_CNT = PG.VOTE_CNT AND VOTE_DATE IS NOT NULL AND (BID_CANCEL_FLAG, '0') = '0' AND DEL_FLAG = '0') AS JOIN_VENDOR_CNT -- 투찰업체수 FROM STOCBDHD HD JOIN STOCBDPG PG ON (HD.GATE_CD = PG.GATE_CD AND HD.BUYER_CD = PG.BUYER_CD AND HD.BID_NUM = PG.BID_NUM AND HD.BID_CNT = PG.BID_CNT AND PG.VOTE_CNT = (SELECT MAX(P.VOTE_CNT) FROM STOCBDPG P WHERE P.GATE_CD = HD.GATE_CD AND P.BUYER_CD = HD.BUYER_CD AND P.BID_NUM = HD.BID_NUM AND P.BID_CNT = HD.BID_CNT AND P.DEL_FLAG = '0')) WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{ses.companyCd} AND HD.DEL_FLAG = '0' AND HD.BID_STATUS NOT IN ('1300', '2500', '9999') -- 유찰, 업체선정, 취소공고건 제외(취소공고 확정건는 STOCBDPG에 등록되지 않기 때문에 조회되지 않음) AND (CASE WHEN ((TO_NUMBER(HD.BID_STATUS) >= 2350 AND TO_NUMBER(HD.BID_STATUS) < 2500) OR HD.BID_STATUS = '2550') THEN '1' ELSE '0' END) = '1' AND HD.SIGN_STATUS = 'E' AND ((TO_CHAR(SYSDATE, 'YYYYMMDD') >= HD.APP_BEGIN_DATE AND TO_CHAR(SYSDATE, 'YYYYMMDD') < HD.APP_END_DATE) OR (TO_CHAR(SYSDATE, 'YYYYMMDD') >= HD.APP_END_DATE OR HD.BID_STATUS IN ('2350','2353','2363','2367')) )
AND (PG.BID_END_DATE, HD.APP_END_DATE) >= #{APP_END_FROM} AND (PG.BID_END_DATE, HD.APP_END_DATE) <= #{APP_END_TO}
AND getBidProgressCd(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, 'CD') = #{BID_STATUS}
AND HD.BID_USER_ID = #{sBID_USER_ID}
AND UPPER(GETUSERNAME(HD.GATE_CD, HD.BID_USER_ID, #{ses.langCd})) LIKE '%' UPPER(#{sBID_USER_NM}) '%'
AND UPPER(HD.ANN_NO) LIKE '%' UPPER(#{ANN_NO}) '%'
AND UPPER(REPLACE(HD.ANN_ITEM, ' ', '')) LIKE '%' UPPER(REPLACE(#{ANN_ITEM}, ' ', '')) '%'
AND EXISTS (SELECT 1 FROM STOCBDDT DT WHERE DT.GATE_CD = HD.GATE_CD AND DT.BUYER_CD = HD.BUYER_CD AND DT.BID_NUM = HD.BID_NUM AND DT.BID_CNT = HD.BID_CNT
AND UPPER(DT.PR_BUYER_CD) LIKE '%' UPPER(#{BUYER_CD}) '%'
AND UPPER(getCustName(DT.GATE_CD, DT.PR_BUYER_CD)) LIKE '%' UPPER(#{BUYER_NM}) '%'
AND DT.DEL_FLAG = '0')
) A LEFT JOIN STOCBDPG PG ON (A.GATE_CD = PG.GATE_CD AND A.BUYER_CD = PG.BUYER_CD AND A.BID_NUM = PG.BID_NUM AND A.BID_CNT = PG.BID_CNT AND A.PRECENT_VOTE = PG.VOTE_CNT AND PG.DEL_FLAG = '0') ORDER BY PG.OPEN_DATE, PG.BID_END_DATE, PG.BID_END_TIME, A.APP_END_DATE

