        SELECT
             getBidProgressCd(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, 'CD') AS PROGRESS_CD
            ,(CASE WHEN SYSDATE >= TO_DATE(PG.OPEN_DATE  PG.OPEN_TIME, 'YYYYMMDDHH24MISS') THEN 'Y' ELSE 'N' END) AS OPEN_POSSIBLE_FLAG
            , HD.OPEN_USER_ID
          FROM STOCBDHD HD 
          JOIN STOCBDPG PG
	           ON (HD.GATE_CD  = PG.GATE_CD
	           AND HD.BUYER_CD = PG.BUYER_CD
	           AND HD.BID_NUM  = PG.BID_NUM
	           AND HD.BID_CNT  = PG.BID_CNT
	           AND PG.VOTE_CNT = #{VOTE_CNT}
	           AND PG.DEL_FLAG = '0')
         WHERE HD.GATE_CD  = #{ses.gateCd}
           AND HD.BUYER_CD = #{BUYER_CD}
           AND HD.BID_NUM  = #{BID_NUM}
           AND HD.BID_CNT  = #{BID_CNT}

