SELECT B.* FROM ( SELECT RANK() OVER (PARTITION BY A.GATE_CD ORDER BY A.CHOICE_CNT DESC) AS CHOICE_RANK ,A.CHOICE_NUM, A.RANDOM_RANK FROM (
SELECT '${item.GATE_CD}' AS GATE_CD, '${item.CHOICE_NUM}' AS CHOICE_NUM, TO_NUMBER('${item.CHOICE_CNT}') AS CHOICE_CNT, CEIL(DBMS_RANDOM.VALUE(1, 15)) AS RANDOM_RANK FROM DUAL
) A ) B ORDER BY B.CHOICE_RANK, B.RANDOM_RANK

SELECT
     A.CHOIC_ESTM_PRC1, A.CHOIC_ESTM_PRC2, A.CHOIC_ESTM_PRC3, A.CHOIC_ESTM_PRC4
    ,ROUND((A.CHOIC_ESTM_PRC1 + A.CHOIC_ESTM_PRC2 + A.CHOIC_ESTM_PRC3 + CHOIC_ESTM_PRC4) / 4) AS FINAL_ESTM_PRC
  FROM (
    SELECT
         '1' AS TMP

        ,${item.COL_ID} AS ${item.COL_NM}

      FROM STOCBDES
     WHERE GATE_CD  = #{ses.gateCd}
       AND BUYER_CD = #{BUYER_CD}
       AND BID_NUM  = #{BID_NUM}
       AND BID_CNT  = #{BID_CNT}
  ) A

