mapper.select:
SELECT HD.ANN_NO, HD.ANN_ITEM ,SUBSTR(HD.ANN_DATE, 1, 4) '-' SUBSTR(HD.ANN_DATE, 5, 2) '-' SUBSTR(HD.ANN_DATE, 7, 2) AS ANN_DATE ,HD.CONT_TYPE1, HD.CONT_TYPE2, HD.CONT_TYPE3, HD.TECH_EV_TYPE ,getContTypeTxt(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, #{ses.langCd}) AS CONT_TYPE_TXT ,HD.BID_USER_ID, HD.OPEN_USER_ID, HD.EV_USER_ID ,HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, HD.BID_STATUS, HD.BID_STATUS AS PRE_BID_STATUS, PG.VOTE_CNT ,HD.DIFF_GUAR_FLAG, HD.ESTM_LIMIT_RATE, HD.VOTE_LIMIT_CNT AS CHECK_VOTE_LIMIT_CNT ,GETCOMCODE(HD.GATE_CD, 'M023', HD.CUR, 0, #{ses.langCd}) AS CUR ,GETCOMCODE(HD.GATE_CD, 'M100', HD.VAT_TYPE, 0, #{ses.langCd}) AS VAT_TYPE ,(SELECT MAX(DT.PR_BUYER_CD) FROM STOCBDDT DT WHERE DT.GATE_CD = HD.GATE_CD AND DT.BUYER_CD = HD.BUYER_CD AND DT.BID_NUM = HD.BID_NUM AND DT.BID_CNT = HD.BID_CNT AND DT.DEL_FLAG = '0') AS PR_BUYER_CD ,(SELECT MAX(PG.VOTE_CNT) FROM STOCBDPG PG WHERE PG.GATE_CD = HD.GATE_CD AND PG.BUYER_CD = HD.BUYER_CD AND PG.BID_NUM = HD.BID_NUM AND PG.BID_CNT = HD.BID_CNT AND PG.DEL_FLAG = '0') AS VOTE_LIMIT_CNT ,HD.FINA_SOLV_FLAG ,HD.RATE_SDEPT ,HD.RATE_CURR ,TO_CHAR((CASE WHEN HD.CONT_TYPE2 = 'QE' THEN NVL ( NVL (HD.BASIC_AMT, HD.PR_AMT), 0) ELSE NVL (HD.PR_AMT, 0) END), 'FM999,999,999,999,999') AS BID_PR_AMT ,TO_CHAR((CASE WHEN HD.ESTM_TYPE IN ('SE', 'PE') THEN NVL ( NVL (ES.FINAL_ESTM_PRC, ES.ESTM_PRC1_ENC ), 0) ELSE 0 END), 'FM999,999,999,999,999') AS ESTM_AMT FROM STOCBDHD HD JOIN STOCBDPG PG ON (HD.GATE_CD = PG.GATE_CD AND HD.BUYER_CD = PG.BUYER_CD AND HD.BID_NUM = PG.BID_NUM AND HD.BID_CNT = PG.BID_CNT AND PG.DEL_FLAG = '0') LEFT JOIN STOCBDES ES ON (HD.GATE_CD = ES.GATE_CD AND HD.BUYER_CD = ES.BUYER_CD AND HD.BID_NUM = ES.BID_NUM AND HD.BID_CNT = ES.BID_CNT AND ES.DEL_FLAG = '0' AND ES.ESTM_CONFIRM_DATE IS NOT NULL) WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{BUYER_CD}
AND HD.BID_NUM = #{BID_NUM} AND HD.BID_CNT = #{BID_CNT} AND PG.VOTE_CNT = #{VOTE_CNT}
AND (HD.RLT_APP_DOC_NUM = #{APP_DOC_NUM} OR HD.NEGO_APP_DOC_NUM = #{APP_DOC_NUM}) AND (HD.RLT_APP_DOC_CNT = #{APP_DOC_CNT} OR HD.NEGO_APP_DOC_CNT = #{APP_DOC_CNT}) AND PG.VOTE_CNT = (SELECT MAX(P.VOTE_CNT) FROM STOCBDPG P WHERE P.GATE_CD = HD.GATE_CD AND P.BUYER_CD = HD.BUYER_CD AND P.BID_NUM = HD.BID_NUM AND P.BID_CNT = HD.BID_CNT AND P.DEL_FLAG = '0')

