 WHERE GATE_CD   = #{ses.gateCd}
   AND BUYER_CD  = #{BUYER_CD}
   AND BID_NUM   = #{BID_NUM}
   AND BID_CNT   = #{BID_CNT}
   AND VOTE_CNT  = #{VOTE_CNT}
   AND VENDOR_CD = #{VENDOR_CD}

UPDATE STOCBDVO SET
      MOD_DATE       = SYSDATE
    , MOD_USER_ID    = #{ses.userId}
    , BID_STATUS     = #{BID_STATUS}
    , SETTLE_DATE	 = (CASE WHEN #{BID_STATUS} = '300' THEN SYSDATE ELSE NULL END)
    , ADJ_PRC_STATUS = #{ADJ_PRC_STATUS}
    , BID_RMK        = #{BID_RMK}
 WHERE GATE_CD   = #{ses.gateCd}
   AND BUYER_CD  = #{BUYER_CD}
   AND BID_NUM   = #{BID_NUM}
   AND BID_CNT   = #{BID_CNT}
   AND VOTE_CNT  = #{VOTE_CNT}
   AND VENDOR_CD = #{VENDOR_CD}

UPDATE STOCBDVO SET
      BID_STATUS = (CASE WHEN BID_STATUS = '200' THEN NULL ELSE BID_STATUS END)
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
 WHERE GATE_CD   = #{ses.gateCd}
   AND BUYER_CD  = #{BUYER_CD}
   AND BID_NUM   = #{BID_NUM}
   AND BID_CNT   = #{BID_CNT}
   AND VOTE_CNT  = TO_NUMBER(#{VOTE_CNT}) - 1
   AND VENDOR_CD = #{VENDOR_CD}

UPDATE STOCBDVO SET
      MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , BID_STATUS = (CASE WHEN BID_STATUS = '200' THEN NULL ELSE BID_STATUS END)
 WHERE GATE_CD   = #{ses.gateCd}
   AND BUYER_CD  = #{BUYER_CD}
   AND BID_NUM   = #{BID_NUM}
   AND BID_CNT   = #{BID_CNT}
   AND VENDOR_CD = #{VENDOR_CD}

        MERGE  STOCBDSP BDSP
        USING (SELECT
                     #{ses.gateCd} AS GATE_CD
                    ,#{BUYER_CD} AS BUYER_CD
                    ,#{BID_NUM} AS BID_NUM
                    ,#{BID_CNT} AS BID_CNT
                    ,#{VOTE_CNT} AS VOTE_CNT
                    ,#{VENDOR_CD} AS VENDOR_CD
                ) B
	          ON (BDSP.GATE_CD   = B.GATE_CD
	          AND BDSP.BUYER_CD  = B.BUYER_CD
	          AND BDSP.BID_NUM   = B.BID_NUM
	          AND BDSP.BID_CNT   = B.BID_CNT
	          AND BDSP.VOTE_CNT  = B.VOTE_CNT
	          AND BDSP.VENDOR_CD = B.VENDOR_CD)
        WHEN MATCHED THEN
        UPDATE SET
             MOD_DATE = SYSDATE
            ,MOD_USER_ID = #{ses.userId}
            ,PRC_SCORE = #{PRC_SCORE}
            ,TECH_SCORE = #{TECH_SCORE}
            ,TECH_ATT_FILE_NUM = #{TECH_ATT_FILE_NUM}
            ,TECH_RMK = #{TECH_RMK}
        WHEN NOT MATCHED THEN
        INSERT (
             GATE_CD
            ,BUYER_CD
            ,BID_NUM
            ,BID_CNT
            ,VOTE_CNT
            ,VENDOR_CD
            ,REG_DATE
            ,REG_USER_ID
            ,MOD_DATE
            ,MOD_USER_ID
            ,DEL_FLAG
            ,PRC_SCORE
            ,TECH_SCORE
            ,TECH_ATT_FILE_NUM
            ,TECH_RMK
        ) VALUES (
             #{ses.gateCd}
            ,#{BUYER_CD}
            ,#{BID_NUM}
            ,#{BID_CNT}
            ,#{VOTE_CNT}
            ,#{VENDOR_CD}
            ,SYSDATE
            ,#{ses.userId}
            ,SYSDATE
