SELECT TO_CHAR(COUNT(*)) FROM STOCBDVO
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND BID_NUM  = #{BID_NUM}
   AND BID_CNT  = #{BID_CNT}
   AND VOTE_CNT = #{VOTE_CNT}
   AND (BID_STATUS, '100') NOT IN ('400', '600')

SELECT TO_CHAR(COUNT(A.BID_STATUS)) AS BID_STATUS_COUNT FROM (
SELECT (CASE WHEN VO.BID_STATUS IS NOT NULL THEN VO.BID_STATUS ELSE (CASE WHEN (GETDECPERSONALINFO(SP.TECH_SCORE), 0) < (HD.MIN_TECH_SCORE, 0) OR (SP.PRC_SCORE, 0) + (GETDECPERSONALINFO(SP.TECH_SCORE), 0) < (HD.MIN_TOT_SCORE, 0) THEN '600' ELSE (CASE WHEN ((AP.FINAL_FLAG, '100') = '600' OR (AP.EV_FINAL_FLAG, '100') = '600') THEN '600' ELSE '100' END) END) END) AS BID_STATUS FROM STOCBDHD HD JOIN STOCBDAP AP ON (HD.GATE_CD = AP.GATE_CD AND HD.BUYER_CD = AP.BUYER_CD AND HD.BID_NUM = AP.BID_NUM AND HD.BID_CNT = AP.BID_CNT AND AP.VENDOR_CD = #{vendorData.VENDOR_CD} AND AP.DEL_FLAG = '0') JOIN STOCBDVO VO ON (AP.GATE_CD = VO.GATE_CD AND AP.BUYER_CD = VO.BUYER_CD AND AP.BID_NUM = VO.BID_NUM AND AP.BID_CNT = VO.BID_CNT AND AP.VENDOR_CD = VO.VENDOR_CD AND VO.VOTE_CNT = #{vendorData.VENDOR_MAX_VOTE_CNT} AND VO.DEL_FLAG = '0') LEFT JOIN STOCBDSP SP ON (SP.GATE_CD = VO.GATE_CD AND SP.BUYER_CD = VO.BUYER_CD AND SP.BID_NUM = VO.BID_NUM AND SP.BID_CNT = VO.BID_CNT AND SP.VOTE_CNT = VO.VOTE_CNT AND SP.VENDOR_CD = VO.VENDOR_CD AND SP.DEL_FLAG = '0') WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{vendorData.BUYER_CD} AND HD.BID_NUM = #{vendorData.BID_NUM} AND HD.BID_CNT = #{vendorData.BID_CNT} AND HD.DEL_FLAG = '0'
) A WHERE (A.BID_STATUS, '100') NOT IN ('400', '600')

SELECT TO_CHAR(COUNT(B.BID_STATUS)) FROM ( SELECT (CASE WHEN A.ORI_BID_STATUS IS NOT NULL THEN A.ORI_BID_STATUS ELSE (CASE WHEN (((A.SB_LIMIT_RATE, 0) / 100) * (ES.FINAL_ESTM_PRC, (A.PR_AMT, 0))) > (A.BID_AMT, 0) OR (ES.FINAL_ESTM_PRC, (A.PR_AMT, 0)) < (A.BID_AMT, 0) THEN '600' ELSE (CASE WHEN A.PASS_FLAG = 'N' THEN '600' ELSE '100' END) END) END) AS BID_STATUS FROM (
SELECT HD.GATE_CD , HD.BUYER_CD , HD.BID_NUM , HD.BID_CNT , AP.VENDOR_CD ,((CASE WHEN ((AP.FINAL_FLAG, '100') = '600' OR (AP.EV_FINAL_FLAG, '100') = '600') THEN 0 ELSE VO.BID_AMT END), 0) AS BID_AMT -- 입찰금액 , VO.BID_STATUS AS ORI_BID_STATUS , HD.SB_LIMIT_RATE -- 낙찰하한율 , HD.PR_AMT -- 기초금액 ,(CASE WHEN ((AP.FINAL_FLAG, '100') = '600' OR (AP.EV_FINAL_FLAG, '100') = '600') THEN 'N' ELSE 'Y' END) AS PASS_FLAG -- 기술평가 적합여부 FROM STOCBDHD HD JOIN STOCBDAP AP ON (HD.GATE_CD = AP.GATE_CD AND HD.BUYER_CD = AP.BUYER_CD AND HD.BID_NUM = AP.BID_NUM AND HD.BID_CNT = AP.BID_CNT AND AP.VENDOR_CD = #{vendorData.VENDOR_CD} AND AP.DEL_FLAG = '0') LEFT JOIN STOCBDVO VO ON (AP.GATE_CD = VO.GATE_CD AND AP.BUYER_CD = VO.BUYER_CD AND AP.BID_NUM = VO.BID_NUM AND AP.BID_CNT = VO.BID_CNT AND AP.VENDOR_CD = VO.VENDOR_CD AND VO.VOTE_CNT = #{vendorData.VENDOR_MAX_VOTE_CNT} AND VO.DEL_FLAG = '0') WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{vendorData.BUYER_CD} AND HD.BID_NUM = #{vendorData.BID_NUM} AND HD.BID_CNT = #{vendorData.BID_CNT} AND HD.DEL_FLAG = '0'
) A LEFT JOIN STOCBDES ES ON (A.GATE_CD = ES.GATE_CD AND A.BUYER_CD = ES.BUYER_CD AND A.BID_NUM = ES.BID_NUM AND A.BID_CNT = ES.BID_CNT AND ES.DEL_FLAG = '0' AND ES.ESTM_CONFIRM_DATE IS NOT NULL) ) B WHERE (B.BID_STATUS, '100') NOT IN ('400', '600')

