SELECT B.PR_BUYER_CD, B.PR_BUYER_NM ,B.ANN_NO, B.BID_CNT, B.ANN_ITEM, B.ANN_DATE ,B.CONT_TYPE1 ,GETCOMCODE(B.GATE_CD, 'M301', B.CONT_TYPE1, 0, #{ses.langCd}) AS CONT_TYPE1_NM ,B.CONT_TYPE2 ,GETCOMCODE(B.GATE_CD, 'M302', B.CONT_TYPE2, 0, #{ses.langCd}) AS CONT_TYPE2_NM ,B.CONT_TYPE3 ,GETCOMCODE(B.GATE_CD, 'M303', B.CONT_TYPE3, 0, #{ses.langCd}) AS CONT_TYPE3_NM ,B.APP_END_DATETIME ,B.BID_END_DATETIME ,B.BID_STATUS, B.BID_STATUS_LOC, B.PRE_BID_STATUS ,B.SETTEL_VENDOR_CD, GL.VENDOR_NM AS SETTEL_VENDOR_NM ,B.BID_USER_ID, B.BID_USER_NM ,B.RLT_APP_DOC_NUM, B.RLT_APP_DOC_CNT ,B.RLT_SIGN_STATUS ,GETCOMCODE(B.GATE_CD, 'M020', B.RLT_SIGN_STATUS, 0, #{ses.langCd}) AS RLT_SIGN_STATUS_NM ,B.RLT_SIGN_DATE ,B.BUYER_CD, B.BID_NUM, B.VOTE_CNT ,B.TECH_EV_TYPE FROM ( SELECT A.PR_BUYER_CD ,getBuyerNames(A.GATE_CD, A.BUYER_CD, 'BID', A.BID_NUM, A.BID_CNT, null, #{ses.langCd}) AS PR_BUYER_NM ,A.ANN_NO, A.BID_CNT, A.ANN_ITEM, A.ANN_DATE ,A.CONT_TYPE1, A.CONT_TYPE2, A.CONT_TYPE3 ,A.APP_END_DATETIME ,A.BID_END_DATETIME ,A.BID_STATUS, A.BID_STATUS_LOC, A.PRE_BID_STATUS ,(CASE WHEN A.BID_STATUS = '2500' THEN (SELECT MAX(VO.VENDOR_CD) FROM STOCBDVO VO WHERE VO.GATE_CD = A.GATE_CD AND VO.BUYER_CD = A.BUYER_CD AND VO.BID_NUM = A.BID_NUM AND VO.BID_CNT = A.BID_CNT AND VO.BID_STATUS = '300' AND VO.DEL_FLAG = '0') ELSE '' END) AS SETTEL_VENDOR_CD ,A.BID_USER_ID, A.BID_USER_NM ,A.RLT_APP_DOC_NUM, A.RLT_APP_DOC_CNT, A.RLT_SIGN_STATUS, A.RLT_SIGN_DATE ,A.GATE_CD, A.BUYER_CD, A.BID_NUM, A.VOTE_CNT ,A.TECH_EV_TYPE FROM ( SELECT (SELECT MAX(DT.PR_BUYER_CD) FROM STOCBDDT DT WHERE DT.GATE_CD = HD.GATE_CD AND DT.BUYER_CD = HD.BUYER_CD AND DT.BID_NUM = HD.BID_NUM AND DT.BID_CNT = HD.BID_CNT AND DT.DEL_FLAG = '0') AS PR_BUYER_CD ,HD.ANN_NO ,HD.ANN_DATE ,HD.BID_CNT ,HD.ANN_ITEM ,HD.CONT_TYPE1, HD.CONT_TYPE2, HD.CONT_TYPE3 ,SUBSTR(HD.APP_END_DATE, 1, 4) '-' SUBSTR(HD.APP_END_DATE, 5, 2) '-' SUBSTR(HD.APP_END_DATE, 7, 2) ' ' SUBSTR(HD.APP_END_TIME, 1, 2) ':' SUBSTR(HD.APP_END_TIME, 3, 2) AS APP_END_DATETIME ,SUBSTR(PG.BID_END_DATE, 1, 4) '-' SUBSTR(PG.BID_END_DATE, 5, 2) '-' SUBSTR(PG.BID_END_DATE, 7, 2) ' ' SUBSTR(PG.BID_END_TIME, 1, 2) ':' SUBSTR(PG.BID_END_TIME, 3, 2) AS BID_END_DATETIME ,HD.BID_STATUS, GETCOMCODE(HD.GATE_CD, 'M340', HD.BID_STATUS, 0, #{ses.langCd}) AS BID_STATUS_LOC, HD.PRE_BID_STATUS ,HD.BID_USER_ID, GETUSERNAME(HD.GATE_CD, HD.BID_USER_ID, #{ses.langCd}) AS BID_USER_NM ,HD.RLT_APP_DOC_NUM, HD.RLT_APP_DOC_CNT, (CASE WHEN HD.BID_STATUS = '1300' THEN HD.RLT_SIGN_STATUS ELSE '' END) AS RLT_SIGN_STATUS, HD.RLT_SIGN_DATE ,HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, PG.VOTE_CNT ,HD.TECH_EV_TYPE FROM STOCBDHD HD JOIN STOCBDPG PG ON (HD.GATE_CD = PG.GATE_CD AND HD.BUYER_CD = PG.BUYER_CD AND HD.BID_NUM = PG.BID_NUM AND HD.BID_CNT = PG.BID_CNT AND PG.VOTE_CNT = (SELECT MAX(P.VOTE_CNT) FROM STOCBDPG P WHERE P.GATE_CD = HD.GATE_CD AND P.BUYER_CD = HD.BUYER_CD AND P.BID_NUM = HD.BID_NUM AND P.BID_CNT = HD.BID_CNT AND P.DEL_FLAG = '0') AND PG.DEL_FLAG = '0') WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{ses.companyCd} AND HD.SIGN_STATUS = 'E' AND HD.BID_STATUS IN ('1300', '2500') AND HD.BID_STATUS != '9999' -- 취소공고건은 제외(취소공고 확정은 STOCBDPG에 등록되지 않기때문에 조회 제외) AND HD.DEL_FLAG = '0'
AND (PG.BID_END_DATE, HD.APP_END_DATE) >= #{BID_END_DATETIME_FROM} AND (PG.BID_END_DATE, HD.APP_END_DATE) <= #{BID_END_DATETIME_TO}
AND HD.BID_STATUS = #{BID_STATUS}
AND UPPER(HD.ANN_NO) LIKE '%' UPPER(#{ANN_NO}) '%'
AND UPPER(REPLACE(HD.ANN_ITEM, ' ', '')) LIKE '%' UPPER(REPLACE(#{ANN_ITEM}, ' ', '')) '%'
AND (HD.RLT_SIGN_STATUS, 'T') = #{RLT_SIGN_STATUS}
AND HD.CONT_TYPE2 IN
#{item}
) A WHERE 1 = 1
AND A.BID_USER_ID = #{sBID_USER_ID}
AND UPPER(A.BID_USER_NM) LIKE '%' UPPER(#{sBID_USER_NM}) '%'
) B LEFT OUTER JOIN STOCVNGL GL ON (B.GATE_CD = GL.GATE_CD AND B.SETTEL_VENDOR_CD = GL.VENDOR_CD) WHERE 1 = 1
AND B.PR_BUYER_CD LIKE '%' UPPER(#{BUYER_CD}) '%'
AND UPPER(B.PR_BUYER_NM) LIKE '%' UPPER(#{BUYER_NM}) '%'
AND B.SETTEL_VENDOR_CD = #{SETTEL_VENDOR_CD}
AND UPPER(GL.VENDOR_NM) LIKE '%' UPPER(#{SETTEL_VENDOR_NM}) '%'
ORDER BY B.BID_END_DATETIME DESC

